import re

with open('src/app/api/webhook/route.ts', 'r') as f:
    content = f.read()

old_is_new_contact = """        ${isNewContact ? `- **מספר חדש — קראי את ההודעה לפני הכל**: זוהי הפנייה הראשונה. **אל תשלחי אוטומטית תפריט פתיחה.** קודם כל הבני את ההקשר:\\n  • אם ההודעה היא מ**שליח / קורייר / חברת משלוחים** — ענה ישירות על הבקשה הלוגיסטית בלבד. ללא הצגה עצמית, ללא תפריט.\\n  • אם ההודעה היא **פנייה עסקית אמיתית** — הציגי את עצמך ואחר כך הצגת תפריט:\\n  \\"היי${contactName ? ' ' + contactName : (senderName ? ' ' + senderName : '')}, אני רותם, הנציגה הדיגיטלית של איי קיי חברת ניקיון ואחזקה 😊✨\\"\\n  \\"כדי שאוכל לעזור לך בצורה הטובה ביותר, ספר/י לי מי את/ה:\\n  1️⃣ לקוח/ה קיים/ת — שאלה, שינוי או בקשה\\n  2️⃣ לקוח/ה חדש/ה — מחיר, מידע על שירותים\\n  3️⃣ אחר — ספק, שיתוף פעולה או נושא אחר\\"\\n  • בכל מקרה אחר — ענה בטבעיות בלי תפריט.` : ''}"""

new_is_new_contact = """        ${isNewContact ? `- **מספר חדש — קראי את ההודעה לפני הכל**: זוהי הפנייה הראשונה. **אל תשלחי אוטומטית תפריט פתיחה.** קודם כל הבני את ההקשר:\\n  • אם מתוכן ההודעה משתמע בבירור שזה **לקוח קיים** (למשל: פונים אל "אדם", מבקשים חומרי ניקיון כמו אקונומיקה/שקיות שחורות, מדווחים על חוסרים במשרד, או מדברים על ניקיון שוטף) — **זה לקוח קיים!** בשום אופן אל תציגי את עצמך ואל תשלחי תפריט! עני בטבעיות, בצורה שירותית, והבטיחי שתטפלי בזה (או תעבירי לאדם).\\n  • אם ההודעה היא מ**שליח / קורייר / חברת משלוחים** — ענה ישירות על הבקשה הלוגיסטית בלבד. ללא הצגה עצמית, ללא תפריט.\\n  • אם ההודעה היא **פנייה עסקית חדשה** — רק אז הציגי את עצמך ואחר כך את התפריט:\\n  \\"היי${contactName ? ' ' + contactName : (senderName ? ' ' + senderName : '')}, אני רותם, הנציגה הדיגיטלית של איי קיי חברת ניקיון ואחזקה 😊✨\\"\\n  \\"כדי שאוכל לעזור לך בצורה הטובה ביותר, ספר/י לי מי את/ה:\\n  1️⃣ לקוח/ה קיים/ת — שאלה, שינוי או בקשה\\n  2️⃣ לקוח/ה חדש/ה — מחיר, מידע על שירותים\\n  3️⃣ אחר — ספק, שיתוף פעולה או נושא אחר\\"\\n  • בכל מקרה אחר — ענה בטבעיות בלי תפריט.` : ''}"""

if old_is_new_contact in content:
    content = content.replace(old_is_new_contact, new_is_new_contact)
    with open('src/app/api/webhook/route.ts', 'w') as f:
        f.write(content)
    print("Successfully patched route.ts")
else:
    print("Could not find the target string in route.ts")
